package javapackage;

public class Foreachloop1 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		//defining an array
		int arr[] = { 1, 2, 3, 4, 5 } ;
		// printing an array using for each loop
		for (int a : arr) {
			System.out.println(a);
		}
	}
}
